#include <stdio.h>

#define MAX_SIZE 10

int stack[MAX_SIZE];
int stackPointer = -1;

void push(int value) {
  if (stackPointer < MAX_SIZE - 1) {
    stackPointer = stackPointer + 1;
    stack[stackPointer] = value;
  } else {
    printf("Stack is full");
  }
}

int pop() {
  if (stackPointer >= 0) {
    int value = stack[stackPointer];
    stackPointer = stackPointer - 1;
    return value;
  } else {
    printf("Stack is empty");
    return -1;
  }
}

int main() {
  push(10);
  push(20);
  printf("Popped value: %d", pop());
  return 0;
}
